#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10,B=500;

struct Edge{
    int to,val;
};

int n;
long long f[N][4],g[980][2],t[980][2];
vector<Edge> e[N];

void dfs(int x,int fa){
	for(Edge y:e[x])
		if(y.to!=fa)
			dfs(y.to,x);
    memset(g,0xcf,sizeof(g));
    g[B][0]=0;
    random_shuffle(e[x].begin(),e[x].end());
    for(Edge y:e[x])
        if(y.to!=fa){
            memset(t,0xcf,sizeof(t));
            int v=y.to,w=y.val; 
            for(int i=-460+B;i<=460+B;i++){
                t[i][0]=max(t[i][0],f[v][0]+g[i][0]);
                t[i][1]=max(t[i][1],f[v][0]+g[i][1]);
                t[i][0]=max(t[i][0],f[v][0]+g[i+1][0]+w);
                t[i][1]=max(t[i][1],f[v][0]+g[i+1][1]+w);
                t[i][0]=max(t[i][0],f[v][1]+g[i][1]+w);
                t[i][1]=max(t[i][1],f[v][1]+g[i][0]+w);
                t[i][0]=max(t[i][0],f[v][2]+g[i-1][0]+w);
                t[i][1]=max(t[i][1],f[v][2]+g[i-1][1]+w);
                t[i][0]=max(t[i][0],f[v][3]+g[i][0]+w);
                t[i][1]=max(t[i][1],f[v][3]+g[i][1]+w);
            }
            for(int i=B-460;i<=B+460;i++)
                g[i][0]=t[i][0],g[i][1]=t[i][1];
        }
    f[x][0]=g[B][0];
    f[x][1]=g[B-1][0];
    f[x][2]=g[B][1];
    f[x][3]=g[B+1][0];
}

int main(){
    scanf("%d",&n);
    for(int i=1,u,v,w;i<n;i++){
        scanf("%d%d%d",&u,&v,&w);
        e[u].push_back({v,w});
        e[v].push_back({u,w});
    }
    dfs(1,0);
    printf("%lld",f[1][0]);
    return 0;
}
